refentry.refsect1:
  &reftitle.description;

&style.procedural;

   intfalsenullgrapheme_strlen
   stringstring



   Функция возвращает количество графемных кластеров в строке, а не длину в байтах или символах.

&reftitle.parameters;




   string



     Строка по стандарту UTF-8, в которой требуется посчитать количество графемных кластеров.

  &reftitle.examples;

   Пример подсчёта графемных кластеров в строке функцией grapheme_strlen


<?php

// Символ | Название | Кодовая точка | Форма нормализации

// å: 'LATIN SMALL LETTER A WITH RING ABOVE', U+00E5, D
$char_a_ring_nfd = "a\xCC\x8A";

// ö: 'LATIN SMALL LETTER O WITH DIAERESIS', U+00F6, D
$char_o_diaeresis_nfd = "o\xCC\x88";

print grapheme_strlen('abc' . $char_a_ring_nfd . $char_o_diaeresis_nfd . $char_a_ring_nfd);



  &example.outputs;


6

&reftitle.seealso;
